- **CLI Commands**:
  - `nest new nest-crud-app`: Creates a new NestJS project.
  - `npm install --save @nestjs/typeorm typeorm pg`: Installs TypeORM and PostgreSQL driver.

- **Latest Versions**:
  - NestJS: v10.0.0
  - TypeORM: v0.3.24

- **Key Config Options**:
  - `app.module.ts`:
    ```typescript
    @Module({
      imports: [
        TypeOrmModule.forRoot({
          type: 'postgres',
          host: 'localhost',
          port: 5432,
          username: 'user',
          password: 'password',
          database: 'database_name',
          entities: [__dirname + '/**/*.entity{.ts,.js}'],
          synchronize: true,
        }),
      ],
    })
    ```
  - Entity Example (`user.entity.ts`):
    ```typescript
    @Entity()
    export class User {
      @PrimaryGeneratedColumn()
      id: number;

      @Column()
      name: string;

      @Column()
      email: string;
    }
    ```
  - Repository Injection:
    ```typescript
    constructor(
      @InjectRepository(User)
      private usersRepository: Repository<User>,
    ) {}
    ```

- **CRUD Operations**:
  - Create: `this.usersRepository.save(user)`
  - Read: `this.usersRepository.findOne(id)`
  - Update: `this.usersRepository.update(id, user)`
  - Delete: `this.usersRepository.delete(id)`

- Use `nest generate service example` and `nest generate module example` to create new services and modules.
- Install latest NestJS and TypeORM using npm or yarn:
  ```bash
  npm install @nestjs/common @nestjs/typeorm typeorm reflect-metadata pg --save
  ```
- Configure TypeORM in `app.module.ts` with the following key options:
  ```typescript
  import { Module } from '@nestjs/common';
  import { TypeOrmModule } from '@nestjs/typeorm';

  @Module({
    imports: [
      TypeOrmModule.forRoot({
        type: 'postgres',
        host: 'localhost',
        port: 5432,
        username: 'user',
        password: 'password',
        database: 'database_name',
        entities: [__dirname + '/**/*.entity{.ts,.js}'],
        synchronize: true,
      }),
    ],
  })
  export class AppModule {}
  ```
- Use the `@InjectRepository` decorator in your service to inject a repository:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { InjectRepository } from '@nestjs/typeorm';
  import { Repository } from 'typeorm';
  import { ExampleEntity } from './example.entity';

  @Injectable()
  export class ExampleService {
    constructor(
      @InjectRepository(ExampleEntity)
      private readonly exampleRepository: Repository<ExampleEntity>,
    ) {}

    async findAll(): Promise<ExampleEntity[]> {
      return this.exampleRepository.find();
    }

    // Implement create, update, and delete methods similarly
  }
  ```
- Ensure your entity is properly defined in `example.entity.ts`:
  ```typescript
  import { Entity, PrimaryGeneratedColumn, Column } from 'typeorm';

  @Entity()
  export class ExampleEntity {
    @PrimaryGeneratedColumn()
    id: number;

    @Column()
    name: string;
  }
  ```
- For unit testing, mock the repository using a library like `ts-mockito` or Jest:
  ```typescript
  import { Test, TestingModule } from '@nestjs/testing';
  import { ExampleService } from './example.service';
  import { Repository } from 'typeorm';
  import { getRepositoryToken } from '@nestjs/typeorm';
  import { ExampleEntity } from './example.entity';

  describe('ExampleService', () => {
    let service: ExampleService;
    let repository: Repository<ExampleEntity>;

    beforeEach(async () => {
      const module: TestingModule = await Test.createTestingModule({
        providers: [
          ExampleService,
          {
            provide: getRepositoryToken(ExampleEntity),
            useClass: Repository,
          },
        ],
      }).compile();

      service = module.get<ExampleService>(ExampleService);
      repository = module.get<Repository<ExampleEntity>>(getRepositoryToken(ExampleEntity));
    });

    it('should be defined', () => {
      expect(service).toBeDefined();
    });
  });
  ```
